1	package handlers
2	
3	import (
4		"fmt"
5		"log"
6		"net/http"
7		"strings"
8	
9		"wlpr-portal/internal/models"
10		"wlpr-portal/internal/repository"
11		"wlpr-portal/internal/services"
12		"wlpr-portal/pkg/crypto"
13	
14		"github.com/labstack/echo/v4"
15	)
16	
17	type AuthHandler struct {
18		authService *services.AuthService
19		mfaService  *services.MFAService
20		userRepo    *repository.UserRepository
21	}
22	
23	func NewAuthHandler(authService *services.AuthService, mfaService *services.MFAService, userRepo *repository.UserRepository) *AuthHandler {
24		return &AuthHandler{
25			authService: authService,
26			mfaService:  mfaService,
27			userRepo:    userRepo,
28		}
29	}
30	
31	// POST /api/auth/login
32	func (h *AuthHandler) Login(c echo.Context) error {
33		var req models.LoginRequest
34		if err := c.Bind(&req); err != nil {
35			return echo.NewHTTPError(http.StatusBadRequest, "invalid request body")
36		}
37		if req.Username == "" || req.Password == "" {
38			return echo.NewHTTPError(http.StatusBadRequest, "username and password are required")
39		}
40	
41		resp, err := h.authService.Login(c.Request().Context(), req, c.RealIP(), c.Request().UserAgent())
42		if err != nil {
43			return echo.NewHTTPError(http.StatusUnauthorized, "invalid credentials")
44		}
45	
46		return c.JSON(http.StatusOK, resp)
47	}
48	
49	// POST /api/auth/mfa/verify
50	func (h *AuthHandler) VerifyMFA(c echo.Context) error {
51		var req models.MFAVerifyRequest
52		if err := c.Bind(&req); err != nil {
53			return echo.NewHTTPError(http.StatusBadRequest, "invalid request body")
54		}
55		if req.Code == "" || req.SessionID == "" {
56			return echo.NewHTTPError(http.StatusBadRequest, "code and session_id are required")
57		}
58	
59		resp, err := h.authService.VerifyMFA(c.Request().Context(), req)
60		if err != nil {
61			return echo.NewHTTPError(http.StatusUnauthorized, "invalid MFA code")
62		}
63	
64		return c.JSON(http.StatusOK, resp)
65	}
66	
67	// POST /api/auth/mfa/setup  (requires auth)
68	func (h *AuthHandler) SetupMFA(c echo.Context) error {
69		userID := c.Get("user_id").(int)
70		username := c.Get("username").(string)
71	
72		secret, provURI, err := h.mfaService.SetupMFA(c.Request().Context(), userID, username)
73		if err != nil {
74			log.Printf("[auth] MFA setup error user=%d: %v", userID, err)
75			return echo.NewHTTPError(http.StatusInternalServerError, "failed to set up MFA")
76		}
77	
78		return c.JSON(http.StatusOK, models.MFASetupResponse{
79			Secret: secret,
80			QRCode: provURI,
81		})
82	}
83	
84	// POST /api/auth/mfa/confirm  (requires auth)
85	func (h *AuthHandler) ConfirmMFA(c echo.Context) error {
86		userID := c.Get("user_id").(int)
87	
88		var body struct {
89			Code string `json:"code"`
90		}
91		if err := c.Bind(&body); err != nil || body.Code == "" {
92			return echo.NewHTTPError(http.StatusBadRequest, "code is required")
93		}
94	
95		recoveryCodes, err := h.mfaService.ConfirmMFA(c.Request().Context(), userID, body.Code)
96		if err != nil {
97			return echo.NewHTTPError(http.StatusBadRequest, "invalid code or MFA not initiated")
98		}
99	
100		return c.JSON(http.StatusOK, map[string]interface{}{
101			"message":        "MFA enabled successfully",
102			"recovery_codes": recoveryCodes,
103		})
104	}
105	
106	// POST /api/auth/mfa/disable  (requires auth)
107	func (h *AuthHandler) DisableMFA(c echo.Context) error {
108		userID := c.Get("user_id").(int)
109	
110		if err := h.mfaService.DisableMFA(c.Request().Context(), userID); err != nil {
111			log.Printf("[auth] MFA disable error user=%d: %v", userID, err)
112			return echo.NewHTTPError(http.StatusInternalServerError, "failed to disable MFA")
113		}
114	
115		return c.JSON(http.StatusOK, map[string]string{"message": "MFA disabled"})
116	}
117	
118	// POST /api/auth/logout  (requires auth)
119	func (h *AuthHandler) Logout(c echo.Context) error {
120		sessionID := c.Get("session_id").(string)
121		userID := c.Get("user_id").(int)
122	
123		if err := h.authService.Logout(c.Request().Context(), sessionID, userID, c.RealIP()); err != nil {
124			log.Printf("[auth] logout error user=%d: %v", userID, err)
125		}
126	
127		return c.JSON(http.StatusOK, map[string]string{"message": "logged out"})
128	}
129	
130	// GET /api/auth/me  (requires auth)
131	func (h *AuthHandler) Me(c echo.Context) error {
132		claims := c.Get("claims")
133		return c.JSON(http.StatusOK, claims)
134	}
135	
136	// POST /api/auth/register  (public)
137	// Users select their role at registration, including system_admin.
138	func (h *AuthHandler) Register(c echo.Context) error {
139		var req models.RegisterRequest
140		if err := c.Bind(&req); err != nil {
141			return echo.NewHTTPError(http.StatusBadRequest, "invalid request body")
142		}
143	
144		if strings.TrimSpace(req.Username) == "" || strings.TrimSpace(req.Email) == "" ||
145			strings.TrimSpace(req.Password) == "" || strings.TrimSpace(req.DisplayName) == "" {
146			return echo.NewHTTPError(http.StatusBadRequest, "username, email, password, and display_name are required")
147		}
148		if len(req.Password) < 8 {
149			return echo.NewHTTPError(http.StatusBadRequest, "password must be at least 8 characters")
150		}
151		if strings.TrimSpace(req.Role) == "" {
152			return echo.NewHTTPError(http.StatusBadRequest, "role is required")
153		}
154		if !models.AllRoles()[req.Role] {
155			return echo.NewHTTPError(http.StatusBadRequest,
156				"invalid role; choose one of: system_admin, learner, procurement_specialist, approver, finance_analyst, content_moderator")
157		}
158	
159		ctx := c.Request().Context()
160	
161		existing, err := h.userRepo.FindByUsername(ctx, req.Username)
162		if err != nil {
163			log.Printf("[auth] find user error: %v", err)
164			return echo.NewHTTPError(http.StatusInternalServerError, "registration temporarily unavailable")
165		}
166		if existing != nil {
167			return echo.NewHTTPError(http.StatusConflict, "username already taken")
168		}
169	
170		hashedPassword, err := crypto.HashPassword(req.Password)
171		if err != nil {
172			log.Printf("[auth] hash error: %v", err)
173			return echo.NewHTTPError(http.StatusInternalServerError, "registration temporarily unavailable")
174		}
175	
176		user, err := h.userRepo.CreateUser(ctx, req.Username, req.Email, hashedPassword,
177			req.DisplayName, req.JobFamily, req.Department, req.CostCenter)
178		if err != nil {
179			if strings.Contains(err.Error(), "duplicate key") {
180				if strings.Contains(err.Error(), "email") {
181					return echo.NewHTTPError(http.StatusConflict, "email already registered")
182				}
183				return echo.NewHTTPError(http.StatusConflict, "username already taken")
184			}
185			log.Printf("[auth] create user error: %v", err)
186			return echo.NewHTTPError(http.StatusInternalServerError, "registration temporarily unavailable")
187		}
188	
189		if err := h.userRepo.AssignRole(ctx, user.ID, req.Role, nil); err != nil {
190			log.Printf("[auth] assign role error user=%d role=%s: %v", user.ID, req.Role, err)
191			return echo.NewHTTPError(http.StatusInternalServerError, "registration succeeded but role assignment failed; contact an administrator")
192		}
193	
194		uwr, err := h.userRepo.GetUserWithRoles(ctx, user.ID)
195		if err != nil {
196			uwr = &models.UserWithRoles{User: *user}
197		}
198	
199		return c.JSON(http.StatusCreated, models.RegisterResponse{
200			Message: fmt.Sprintf("Registration successful. You have been assigned the %s role.",
201				strings.ReplaceAll(req.Role, "_", " ")),
202			User: uwr,
203		})
204	}
205	
206	// GET /api/admin/users  (admin only)
207	func (h *AuthHandler) ListUsers(c echo.Context) error {
208		users, err := h.userRepo.GetAllUsers(c.Request().Context())
209		if err != nil {
210			log.Printf("[admin] list users error: %v", err)
211			return echo.NewHTTPError(http.StatusInternalServerError, "failed to retrieve users")
212		}
213		return c.JSON(http.StatusOK, users)
214	}
215	
216	// POST /api/admin/users/assign-role  (admin only)
217	func (h *AuthHandler) AssignRole(c echo.Context) error {
218		var req models.AssignRoleRequest
219		if err := c.Bind(&req); err != nil {
220			return echo.NewHTTPError(http.StatusBadRequest, "invalid request body")
221		}
222		if req.UserID == 0 || req.Role == "" {
223			return echo.NewHTTPError(http.StatusBadRequest, "user_id and role are required")
224		}
225	
226		if !models.AllRoles()[req.Role] {
227			return echo.NewHTTPError(http.StatusBadRequest, "invalid role name")
228		}
229	
230		adminID := c.Get("user_id").(int)
231		if err := h.userRepo.AssignRole(c.Request().Context(), req.UserID, req.Role, &adminID); err != nil {
232			log.Printf("[admin] assign role error user=%d role=%s: %v", req.UserID, req.Role, err)
233			return echo.NewHTTPError(http.StatusInternalServerError, "failed to assign role")
234		}
235	
236		return c.JSON(http.StatusOK, map[string]string{
237			"message": fmt.Sprintf("role '%s' assigned to user %d", req.Role, req.UserID),
238		})
239	}
