94	// TransitionSettlement validates and executes settlement status transitions.
95	// Valid transitions:
96	//
97	//	open -> matched
98	//	matched -> variance_pending
99	//	variance_pending -> writeoff_suggested
100	//	writeoff_suggested -> writeoff_approved (requires Finance approval)
101	//	writeoff_approved -> settled
102	//	any open state -> disputed
103	//	matched -> settled (no variance)
104	func (s *ReconciliationService) TransitionSettlement(ctx context.Context, req models.SettlementTransitionRequest, userID int) error {
105		settlement, err := s.procRepo.GetSettlementByID(ctx, req.SettlementID)
106		if err != nil || settlement == nil {
107			return fmt.Errorf("settlement not found")
108		}
109	
110		currentStatus := settlement.Status
111		var newStatus string
112	
113		switch req.Action {
114		case "match":
115			if currentStatus != "open" {
116				return fmt.Errorf("invalid transition: cannot match from status %s", currentStatus)
117			}
118			newStatus = "matched"
119	
120		case "flag_variance":
121			if currentStatus != "matched" {
122				return fmt.Errorf("invalid transition: cannot flag variance from status %s", currentStatus)
123			}
124			newStatus = "variance_pending"
125	
126		case "suggest_writeoff":
127			if currentStatus != "variance_pending" {
128				return fmt.Errorf("invalid transition: cannot suggest write-off from status %s", currentStatus)
129			}
130			// Validate variance is below threshold for auto-suggest
131			threshold := 5.00
132			if val, ok := s.configSvc.GetConfig("variance.auto_writeoff_threshold"); ok {
133				fmt.Sscanf(val, "%f", &threshold)
134			}
135			if math.Abs(settlement.VarianceAmount) >= threshold {
136				return fmt.Errorf("variance $%.2f exceeds auto write-off threshold $%.2f; requires manual investigation", math.Abs(settlement.VarianceAmount), threshold)
137			}
138			newStatus = "writeoff_suggested"
139	
140		case "approve_writeoff":
141			if currentStatus != "writeoff_suggested" {
142				return fmt.Errorf("invalid transition: cannot approve write-off from status %s", currentStatus)
143			}
144			newStatus = "writeoff_approved"
145	
146		case "settle":
147			if currentStatus != "matched" && currentStatus != "writeoff_approved" {
148				return fmt.Errorf("invalid transition: cannot settle from status %s", currentStatus)
149			}
150			newStatus = "settled"
151	
152		case "dispute":
153			if currentStatus == "settled" || currentStatus == "disputed" {
154				return fmt.Errorf("invalid transition: cannot dispute from status %s", currentStatus)
155			}
156			newStatus = "disputed"
157	
158		default:
159			return fmt.Errorf("unknown action: %s", req.Action)
160		}
161	
162		return s.procRepo.UpdateSettlement(ctx, req.SettlementID, newStatus, &userID, req.Notes)
163	}
164	
165	// TransitionDispute validates and executes dispute state transitions.
166	// The DB trigger trg_dispute_state_machine also enforces this, providing defense-in-depth.
167	//
168	// Valid transitions:
169	//
170	//	created -> evidence_uploaded
171	//	evidence_uploaded -> under_review
172	//	under_review -> arbitration
173	//	arbitration -> resolved_hidden | resolved_disclaimer | resolved_restored | rejected
174	func (s *ReconciliationService) TransitionDispute(ctx context.Context, req models.DisputeTransitionRequest, userID int) error {
175		dispute, err := s.procRepo.GetDisputeByID(ctx, req.DisputeID)
176		if err != nil || dispute == nil {
177			return fmt.Errorf("dispute not found")
178		}
179	
180		currentStatus := dispute.Status
181		var newStatus string
182		updates := make(map[string]interface{})
183	
184		switch req.Action {
185		case "upload_evidence":
186			if currentStatus != "created" {
187				return fmt.Errorf("invalid transition: cannot upload evidence from status %s (must be 'created')", currentStatus)
188			}
189			if len(req.EvidenceURLs) == 0 {
190				return fmt.Errorf("at least one evidence URL is required")
191			}
192			newStatus = "evidence_uploaded"
193			updates["evidence_urls"] = req.EvidenceURLs
194	
195		case "start_review":
196			if currentStatus != "evidence_uploaded" {
197				return fmt.Errorf("invalid transition: cannot start review from status %s (must be 'evidence_uploaded')", currentStatus)
198			}
199			newStatus = "under_review"
200	
201		case "respond":
202			if currentStatus != "evidence_uploaded" && currentStatus != "under_review" {
203				return fmt.Errorf("merchant can only respond during evidence_uploaded or under_review phase")
204			}
205			if req.MerchantResponse == "" {
206				return fmt.Errorf("merchant_response is required")
207			}
208			// Merchant response doesn't change state, just records the response
209			updates["merchant_response"] = req.MerchantResponse
210			newStatus = currentStatus // no state change for response
211	
212		case "escalate_arbitration":
213			if currentStatus != "under_review" {
214				return fmt.Errorf("invalid transition: cannot escalate to arbitration from status %s (must be 'under_review')", currentStatus)
215			}
216			newStatus = "arbitration"
217	
218		case "arbitrate":
219			if currentStatus != "arbitration" {
220				return fmt.Errorf("invalid transition: cannot arbitrate from status %s (must be 'arbitration')", currentStatus)
221			}
222			outcome := req.ArbitrationOutcome
223			if outcome != "hide" && outcome != "disclaimer" && outcome != "restore" {
224				return fmt.Errorf("arbitration_outcome must be 'hide', 'disclaimer', or 'restore'")
225			}
226	
227			switch outcome {
228			case "hide":
229				newStatus = "resolved_hidden"
230			case "disclaimer":
231				newStatus = "resolved_disclaimer"
232			case "restore":
233				newStatus = "resolved_restored"
234			}
235	
236			updates["arbitration_notes"] = req.ArbitrationNotes
237			updates["arbitration_outcome"] = outcome
238			updates["arbitrated_by"] = userID
239	
240		case "reject":
241			if currentStatus != "arbitration" {
242				return fmt.Errorf("invalid transition: cannot reject from status %s (must be 'arbitration')", currentStatus)
243			}
244			newStatus = "rejected"
245			updates["arbitration_notes"] = req.ArbitrationNotes
246			updates["arbitrated_by"] = userID
247	
248		default:
249			return fmt.Errorf("unknown dispute action: %s", req.Action)
250		}
251	
252		// If merchant response (no state change), handle separately
253		if req.Action == "respond" {
254			return s.procRepo.TransitionDispute(ctx, req.DisputeID, currentStatus, updates)
255		}
256	
257		err = s.procRepo.TransitionDispute(ctx, req.DisputeID, newStatus, updates)
258		if err != nil {
259			return fmt.Errorf("transition failed: %w", err)
260		}
261	
262		// Apply review status change based on arbitration outcome
263		if req.Action == "arbitrate" || req.Action == "reject" {
264			return s.applyArbitrationOutcome(ctx, dispute.ReviewID, newStatus, req.ArbitrationNotes)
265		}
266	
267		return nil
268	}
269	
270	// applyArbitrationOutcome updates the vendor review based on dispute resolution.
271	func (s *ReconciliationService) applyArbitrationOutcome(ctx context.Context, reviewID int, disputeStatus, notes string) error {
272		switch disputeStatus {
273		case "resolved_hidden":
274			return s.procRepo.UpdateReviewStatus(ctx, reviewID, "hidden", "")
275		case "resolved_disclaimer":
276			disclaimer := "This review is subject to a resolved dispute."
277			if notes != "" {
278				disclaimer = notes
279			}
280			return s.procRepo.UpdateReviewStatus(ctx, reviewID, "disclaimer", disclaimer)
281		case "resolved_restored":
282			return s.procRepo.UpdateReviewStatus(ctx, reviewID, "visible", "")
283		case "rejected":
284			// Dispute rejected = review stays visible
285			return s.procRepo.UpdateReviewStatus(ctx, reviewID, "visible", "")
286		}
287		return nil
288	}
