207	func (h *AuthHandler) ListUsers(c echo.Context) error {
208		users, err := h.userRepo.GetAllUsers(c.Request().Context())
209		if err != nil {
210			log.Printf("[admin] list users error: %v", err)
211			return echo.NewHTTPError(http.StatusInternalServerError, "failed to retrieve users")
212		}
213		return c.JSON(http.StatusOK, users)
214	}
