1	package middleware
2	
3	import (
4		"net/http"
5		"strings"
6	
7		"wlpr-portal/internal/services"
8		"wlpr-portal/pkg/jwt"
9	
10		"github.com/labstack/echo/v4"
11	)
12	
13	type AuthMiddleware struct {
14		authService   *services.AuthService
15		configService *services.ConfigService
16	}
17	
18	func NewAuthMiddleware(authService *services.AuthService, configService *services.ConfigService) *AuthMiddleware {
19		return &AuthMiddleware{
20			authService:   authService,
21			configService: configService,
22		}
23	}
24	
25	// RequireAuth validates the JWT, checks session validity (idle/max), and injects claims into context.
26	func (m *AuthMiddleware) RequireAuth() echo.MiddlewareFunc {
27		return func(next echo.HandlerFunc) echo.HandlerFunc {
28			return func(c echo.Context) error {
29				authHeader := c.Request().Header.Get("Authorization")
30				if authHeader == "" {
31					return echo.NewHTTPError(http.StatusUnauthorized, "missing authorization header")
32				}
33	
34				parts := strings.SplitN(authHeader, " ", 2)
35				if len(parts) != 2 || strings.ToLower(parts[0]) != "bearer" {
36					return echo.NewHTTPError(http.StatusUnauthorized, "invalid authorization format")
37				}
38	
39				claims, err := jwt.ValidateToken(parts[1])
40				if err != nil {
41					return echo.NewHTTPError(http.StatusUnauthorized, "invalid or expired token")
42				}
43	
44				// Validate session (idle timeout / max lifetime)
45				session, err := m.authService.ValidateSession(c.Request().Context(), claims.SessionID)
46				if err != nil || session == nil {
47					return echo.NewHTTPError(http.StatusUnauthorized, "session expired")
48				}
49	
50				// Store claims in context for downstream handlers
51				c.Set("claims", claims)
52				c.Set("user_id", claims.UserID)
53				c.Set("username", claims.Username)
54				c.Set("roles", claims.Roles)
55				c.Set("permissions", claims.Permissions)
56				c.Set("session_id", claims.SessionID)
57	
58				return next(c)
59			}
60		}
61	}
62	
63	// RequireRole checks that the authenticated user has at least one of the specified roles.
64	// Returns 404 Not Found (not 403) so unauthorized users cannot discover that a feature exists.
65	func (m *AuthMiddleware) RequireRole(roles ...string) echo.MiddlewareFunc {
66		return func(next echo.HandlerFunc) echo.HandlerFunc {
67			return func(c echo.Context) error {
68				userRoles, ok := c.Get("roles").([]string)
69				if !ok || len(userRoles) == 0 {
70					return echo.NewHTTPError(http.StatusNotFound)
71				}
72	
73				for _, required := range roles {
74					for _, userRole := range userRoles {
75						if required == userRole {
76							return next(c)
77						}
78					}
79				}
80	
81				// Feature invisibility: user without the role should not know the endpoint exists
82				return echo.NewHTTPError(http.StatusNotFound)
83			}
84		}
85	}
86	
87	// RequirePermission checks that the authenticated user has at least one of the specified permissions.
88	// Returns 404 Not Found (not 403) so unauthorized users cannot discover that a feature exists.
89	func (m *AuthMiddleware) RequirePermission(perms ...string) echo.MiddlewareFunc {
90		return func(next echo.HandlerFunc) echo.HandlerFunc {
91			return func(c echo.Context) error {
92				userPerms, ok := c.Get("permissions").([]string)
93				if !ok || len(userPerms) == 0 {
94					return echo.NewHTTPError(http.StatusNotFound)
95				}
96	
97				for _, required := range perms {
98					for _, userPerm := range userPerms {
99						if required == userPerm {
100							return next(c)
101						}
102					}
103				}
104	
105				return echo.NewHTTPError(http.StatusNotFound)
106			}
107		}
108	}
109	
110	// AppVersionCheck middleware checks the client's app version header and enforces compatibility.
111	func (m *AuthMiddleware) AppVersionCheck() echo.MiddlewareFunc {
112		return func(next echo.HandlerFunc) echo.HandlerFunc {
113			return func(c echo.Context) error {
114				clientVersion := c.Request().Header.Get("X-App-Version")
115				if clientVersion == "" {
116					return next(c) // Allow requests without version header (browser clients)
117				}
118	
119				minVersion, _ := m.configService.GetConfig("app.min_supported_version")
120				if minVersion == "" {
121					return next(c)
122				}
123	
124				if compareVersions(clientVersion, minVersion) < 0 {
125					// Check if within read-only grace period
126					c.Set("read_only", true)
127					c.Response().Header().Set("X-App-Deprecated", "true")
128					c.Response().Header().Set("X-Min-Version", minVersion)
129	
130					// Block write operations
131					method := c.Request().Method
132					if method == "POST" || method == "PUT" || method == "PATCH" || method == "DELETE" {
133						return echo.NewHTTPError(http.StatusUpgradeRequired,
134							"client version unsupported; upgrade to "+minVersion+" or later")
135					}
136				}
137	
138				return next(c)
139			}
140		}
141	}
142	
143	// compareVersions compares semver strings. Returns -1, 0, or 1.
144	func compareVersions(a, b string) int {
145		partsA := strings.Split(a, ".")
146		partsB := strings.Split(b, ".")
147	
148		maxLen := len(partsA)
149		if len(partsB) > maxLen {
150			maxLen = len(partsB)
151		}
152	
153		for i := 0; i < maxLen; i++ {
154			var va, vb int
155			if i < len(partsA) {
156				for _, ch := range partsA[i] {
157					if ch >= '0' && ch <= '9' {
158						va = va*10 + int(ch-'0')
159					}
160				}
161			}
162			if i < len(partsB) {
163				for _, ch := range partsB[i] {
164					if ch >= '0' && ch <= '9' {
165						vb = vb*10 + int(ch-'0')
166					}
167				}
168			}
169			if va < vb {
170				return -1
171			}
172			if va > vb {
173				return 1
174			}
175		}
176		return 0
177	}
