24	// CompareStatement compares a vendor's statement total against ledger entries.
25	// If variance < threshold -> PENDING_APPROVAL (auto-suggest write-off).
26	// If variance >= threshold -> MANUAL_INVESTIGATION.
27	func (s *ReconciliationService) CompareStatement(ctx context.Context, req models.CompareStatementRequest) (*models.CompareStatementResponse, error) {
28		if req.VendorID <= 0 {
29			return nil, fmt.Errorf("vendor_id is required")
30		}
31	
32		// Sum AR entries for the vendor in the period
33		ledgerTotal, err := s.procRepo.SumLedgerByVendor(ctx, req.VendorID, "AR", req.PeriodStart, req.PeriodEnd)
34		if err != nil {
35			return nil, fmt.Errorf("failed to sum ledger: %w", err)
36		}
37	
38		variance := req.StatementTotal - ledgerTotal
39		variancePct := 0.0
40		if ledgerTotal != 0 {
41			variancePct = math.Round((variance/ledgerTotal)*10000) / 100
42		}
43	
44		// Get write-off threshold from config (default $5.00)
45		threshold := 5.00
46		if val, ok := s.configSvc.GetConfig("variance.auto_writeoff_threshold"); ok {
47			fmt.Sscanf(val, "%f", &threshold)
48		}
49	
50		absVariance := math.Abs(variance)
51		autoWriteoff := absVariance < threshold && absVariance > 0
52		suggestedState := "matched"
53		if absVariance > 0 {
54			if absVariance < threshold {
55				suggestedState = "pending_approval"
56			} else {
57				suggestedState = "manual_investigation"
58			}
59		}
60	
61		return &models.CompareStatementResponse{
62			VendorID:       req.VendorID,
63			StatementTotal: req.StatementTotal,
64			LedgerTotal:    ledgerTotal,
65			Variance:       math.Round(variance*100) / 100,
66			VariancePct:    variancePct,
67			AutoWriteoff:   autoWriteoff,
68			SuggestedState: suggestedState,
69		}, nil
70	}
