72	// MatchInvoice matches an invoice to an order, computing variance and auto-classifying.
73	func (s *ReconciliationService) MatchInvoice(ctx context.Context, invoiceID, orderID, userID int) error {
74		order, err := s.procRepo.GetOrderByID(ctx, orderID)
75		if err != nil || order == nil {
76			return fmt.Errorf("order not found")
77		}
78		if order.Status != "fulfilled" && order.Status != "partially_fulfilled" && order.Status != "approved" {
79			return fmt.Errorf("order must be in fulfilled/approved status to match; current: %s", order.Status)
80		}
81	
82		invoice, err := s.procRepo.GetInvoiceByID(ctx, invoiceID)
83		if err != nil || invoice == nil {
84			return fmt.Errorf("invoice not found")
85		}
86		if invoice.Status != "pending" {
87			return fmt.Errorf("invoice must be in pending status to match; current: %s", invoice.Status)
88		}
89	
90		// The SQL in MatchInvoice computes variance and auto-classifies via the DB trigger
91		return s.procRepo.MatchInvoice(ctx, invoiceID, orderID, userID)
92	}
