32		configs, err := s.configRepo.GetAllConfigs(ctx)
33		if err != nil {
34			return err
35		}
36		flags, err := s.configRepo.GetAllFeatureFlags(ctx)
37		if err != nil {
38			return err
39		}
40	
41		s.mu.Lock()
42		defer s.mu.Unlock()
43	
44		s.configs = make(map[string]models.Config, len(configs))
45		for _, c := range configs {
46			s.configs[c.Key] = c
47		}
48	
49		s.flags = make(map[string]models.FeatureFlag, len(flags))
50		for _, f := range flags {
51			s.flags[f.Key] = f
52		}
53	
54		return nil
55	}
56	
57	// StartBackgroundSync periodically refreshes the in-memory cache from DB.
58	func (s *ConfigService) StartBackgroundSync(ctx context.Context, interval time.Duration) {
59		go func() {
60			ticker := time.NewTicker(interval)
61			defer ticker.Stop()
62			for {
63				select {
64				case <-ctx.Done():
65					return
66				case <-ticker.C:
67					if err := s.LoadAll(ctx); err != nil {
68						log.Printf("[config-sync] failed to reload configs: %v", err)
69					}
70				}
71			}
72		}()
73	}
74	
75	// GetConfig returns a cached config value. Falls through to DB on cache miss.
76	func (s *ConfigService) GetConfig(key string) (string, bool) {
77		s.mu.RLock()
78		defer s.mu.RUnlock()
79		c, ok := s.configs[key]
80		if !ok {
81			return "", false
82		}
83		return c.Value, true
84	}
85	
86	// GetAllConfigs returns all cached configs.
87	func (s *ConfigService) GetAllConfigs() []models.Config {
88		s.mu.RLock()
89		defer s.mu.RUnlock()
90		result := make([]models.Config, 0, len(s.configs))
91		for _, c := range s.configs {
92			result = append(result, c)
93		}
94		return result
95	}
96	
97	// GetAllFlags returns all cached feature flags.
98	func (s *ConfigService) GetAllFlags() []models.FeatureFlag {
99		s.mu.RLock()
100		defer s.mu.RUnlock()
101		result := make([]models.FeatureFlag, 0, len(s.flags))
102		for _, f := range s.flags {
103			result = append(result, f)
104		}
105		return result
106	}
107	
108	// IsFlagEnabled checks if a feature flag is enabled for a given user's roles.
109	func (s *ConfigService) IsFlagEnabled(key string, userRoleIDs []int) bool {
110		s.mu.RLock()
111		defer s.mu.RUnlock()
112	
113		f, ok := s.flags[key]
114		if !ok || !f.Enabled {
115			return false
116		}
117	
118		switch f.RolloutStrategy {
119		case "all":
120			return true
121		case "disabled":
122			return false
123		case "role_based":
124			for _, allowed := range f.AllowedRoles {
125				for _, userRole := range userRoleIDs {
126					if allowed == userRole {
127						return true
128					}
129				}
130			}
131			return false
132		case "percentage":
133			// For percentage-based, we use a deterministic hash of the key
134			// In a real impl, you'd hash user_id + flag_key for consistent bucketing.
135			// For now, just check if the percentage > 0 means enabled.
136			return f.RolloutPercentage > 0
137		default:
138			return false
139		}
140	}
141	
142	// UpdateConfig updates a config in DB and refreshes cache.
143	func (s *ConfigService) UpdateConfig(ctx context.Context, key, value string, updatedBy int) error {
144		if err := s.configRepo.UpdateConfig(ctx, key, value, updatedBy); err != nil {
145			return err
146		}
147		return s.LoadAll(ctx)
148	}
149	
150	// UpdateFeatureFlag updates a flag in DB and refreshes cache.
151	func (s *ConfigService) UpdateFeatureFlag(ctx context.Context, key string, req models.FeatureFlagUpdateRequest) error {
152		if err := s.configRepo.UpdateFeatureFlag(ctx, key, req); err != nil {
153			return err
154		}
155		return s.LoadAll(ctx)
156	}
