8	// classifyVariance is the pure variance classification logic extracted from
9	// ReconciliationService.CompareStatement for direct unit testing.
10	// It mirrors the exact logic in reconciliation.go lines 54-63.
11	func classifyVariance(invoiceAmount, orderAmount, threshold float64) (suggestedState string, autoWriteoff bool) {
12		variance := invoiceAmount - orderAmount
13		absVariance := math.Abs(variance)
14	
15		autoWriteoff = absVariance < threshold && absVariance > 0
16		suggestedState = "matched"
17		if absVariance > 0 {
18			if absVariance < threshold {
19				suggestedState = "pending_approval"
20			} else {
21				suggestedState = "manual_investigation"
22			}
23		}
24		return
25	}
26	
27	// TestVariance_BelowThreshold proves that variance < $5.00 yields PENDING_APPROVAL.
28	func TestVariance_BelowThreshold(t *testing.T) {
29		threshold := 5.00
30	
31		tests := []struct {
32			name           string
33			invoiceAmt     float64
34			orderAmt       float64
35			wantState      string
36			wantAutoWO     bool
37		}{
38			{
39				name:       "variance $0.01 positive",
40				invoiceAmt: 100.01,
41				orderAmt:   100.00,
42				wantState:  "pending_approval",
43				wantAutoWO: true,
44			},
45			{
46				name:       "variance $0.01 negative",
47				invoiceAmt: 99.99,
48				orderAmt:   100.00,
49				wantState:  "pending_approval",
50				wantAutoWO: true,
51			},
52			{
53				name:       "variance $3.00 (under threshold)",
54				invoiceAmt: 8753.50,
55				orderAmt:   8750.50,
56				wantState:  "pending_approval",
57				wantAutoWO: true,
58			},
59			{
60				name:       "variance $4.99 (just under threshold)",
61				invoiceAmt: 1004.99,
62				orderAmt:   1000.00,
63				wantState:  "pending_approval",
64				wantAutoWO: true,
65			},
66			{
67				name:       "variance -$2.50 negative (absolute below threshold)",
68				invoiceAmt: 997.50,
69				orderAmt:   1000.00,
70				wantState:  "pending_approval",
71				wantAutoWO: true,
72			},
73		}
74	
75		for _, tc := range tests {
76			t.Run(tc.name, func(t *testing.T) {
77				state, autoWO := classifyVariance(tc.invoiceAmt, tc.orderAmt, threshold)
78				if state != tc.wantState {
79					t.Errorf("state: got %q, want %q", state, tc.wantState)
80				}
81				if autoWO != tc.wantAutoWO {
82					t.Errorf("autoWriteoff: got %v, want %v", autoWO, tc.wantAutoWO)
83				}
84			})
85		}
86	}
