15	)
16	
17	type AuthHandler struct {
18		authService *services.AuthService
19		mfaService  *services.MFAService
20		userRepo    *repository.UserRepository
21	}
22	
23	func NewAuthHandler(authService *services.AuthService, mfaService *services.MFAService, userRepo *repository.UserRepository) *AuthHandler {
24		return &AuthHandler{
25			authService: authService,
26			mfaService:  mfaService,
27			userRepo:    userRepo,
28		}
29	}
30	
31	// POST /api/auth/login
32	func (h *AuthHandler) Login(c echo.Context) error {
33		var req models.LoginRequest
34		if err := c.Bind(&req); err != nil {
35			return echo.NewHTTPError(http.StatusBadRequest, "invalid request body")
36		}
37		if req.Username == "" || req.Password == "" {
38			return echo.NewHTTPError(http.StatusBadRequest, "username and password are required")
39		}
40	
41		resp, err := h.authService.Login(c.Request().Context(), req, c.RealIP(), c.Request().UserAgent())
42		if err != nil {
43			return echo.NewHTTPError(http.StatusUnauthorized, "invalid credentials")
44		}
45	
46		return c.JSON(http.StatusOK, resp)
47	}
48	
49	// POST /api/auth/mfa/verify
50	func (h *AuthHandler) VerifyMFA(c echo.Context) error {
51		var req models.MFAVerifyRequest
52		if err := c.Bind(&req); err != nil {
53			return echo.NewHTTPError(http.StatusBadRequest, "invalid request body")
54		}
55		if req.Code == "" || req.SessionID == "" {
56			return echo.NewHTTPError(http.StatusBadRequest, "code and session_id are required")
57		}
58	
59		resp, err := h.authService.VerifyMFA(c.Request().Context(), req)
60		if err != nil {
61			return echo.NewHTTPError(http.StatusUnauthorized, "invalid MFA code")
62		}
63	
64		return c.JSON(http.StatusOK, resp)
65	}
66	
67	// POST /api/auth/mfa/setup  (requires auth)
68	func (h *AuthHandler) SetupMFA(c echo.Context) error {
69		userID := c.Get("user_id").(int)
70		username := c.Get("username").(string)
71	
72		secret, provURI, err := h.mfaService.SetupMFA(c.Request().Context(), userID, username)
73		if err != nil {
74			log.Printf("[auth] MFA setup error user=%d: %v", userID, err)
75			return echo.NewHTTPError(http.StatusInternalServerError, "failed to set up MFA")
76		}
77	
78		return c.JSON(http.StatusOK, models.MFASetupResponse{
79			Secret: secret,
80			QRCode: provURI,
81		})
82	}
83	
84	// POST /api/auth/mfa/confirm  (requires auth)
85	func (h *AuthHandler) ConfirmMFA(c echo.Context) error {
86		userID := c.Get("user_id").(int)
87	
88		var body struct {
89			Code string `json:"code"`
90		}
91		if err := c.Bind(&body); err != nil || body.Code == "" {
92			return echo.NewHTTPError(http.StatusBadRequest, "code is required")
93		}
94	
95		recoveryCodes, err := h.mfaService.ConfirmMFA(c.Request().Context(), userID, body.Code)
96		if err != nil {
97			return echo.NewHTTPError(http.StatusBadRequest, "invalid code or MFA not initiated")
98		}
99	
100		return c.JSON(http.StatusOK, map[string]interface{}{
101			"message":        "MFA enabled successfully",
102			"recovery_codes": recoveryCodes,
103		})
104	}
105	
106	// POST /api/auth/mfa/disable  (requires auth)
107	func (h *AuthHandler) DisableMFA(c echo.Context) error {
108		userID := c.Get("user_id").(int)
109	
110		if err := h.mfaService.DisableMFA(c.Request().Context(), userID); err != nil {
111			log.Printf("[auth] MFA disable error user=%d: %v", userID, err)
112			return echo.NewHTTPError(http.StatusInternalServerError, "failed to disable MFA")
113		}
114	
115		return c.JSON(http.StatusOK, map[string]string{"message": "MFA disabled"})
116	}
117	
118	// POST /api/auth/logout  (requires auth)
119	func (h *AuthHandler) Logout(c echo.Context) error {
120		sessionID := c.Get("session_id").(string)
121		userID := c.Get("user_id").(int)
122	
123		if err := h.authService.Logout(c.Request().Context(), sessionID, userID, c.RealIP()); err != nil {
124			log.Printf("[auth] logout error user=%d: %v", userID, err)
125		}
126	
127		return c.JSON(http.StatusOK, map[string]string{"message": "logged out"})
128	}
129	
130	// GET /api/auth/me  (requires auth)
131	func (h *AuthHandler) Me(c echo.Context) error {
132		claims := c.Get("claims")
133		return c.JSON(http.StatusOK, claims)
134	}
135	
136	// POST /api/auth/register  (public)
137	// The first user to register is auto-assigned system_admin (bootstrap).
138	// All subsequent users may only self-select non-privileged roles.
139	// Privileged roles (system_admin) are assigned by an admin via /api/admin/users/assign-role.
140	func (h *AuthHandler) Register(c echo.Context) error {
141		var req models.RegisterRequest
142		if err := c.Bind(&req); err != nil {
143			return echo.NewHTTPError(http.StatusBadRequest, "invalid request body")
144		}
145	
146		if strings.TrimSpace(req.Username) == "" || strings.TrimSpace(req.Email) == "" ||
147			strings.TrimSpace(req.Password) == "" || strings.TrimSpace(req.DisplayName) == "" {
148			return echo.NewHTTPError(http.StatusBadRequest, "username, email, password, and display_name are required")
149		}
150		if len(req.Password) < 8 {
151			return echo.NewHTTPError(http.StatusBadRequest, "password must be at least 8 characters")
152		}
153	
154		ctx := c.Request().Context()
155	
156		// Check if this is the very first user (bootstrap: auto-assign system_admin)
157		userCount, err := h.userRepo.CountUsers(ctx)
158		if err != nil {
159			log.Printf("[auth] count users error: %v", err)
160			return echo.NewHTTPError(http.StatusInternalServerError, "registration temporarily unavailable")
161		}
162		isFirstUser := userCount == 0
163	
164		var assignedRole string
165		if isFirstUser {
166			// First user bootstrap: ignore the requested role and assign system_admin
167			assignedRole = "system_admin"
168		} else {
169			// Subsequent users: validate role from the safe self-registration set
170			if strings.TrimSpace(req.Role) == "" {
171				return echo.NewHTTPError(http.StatusBadRequest, "role is required")
172			}
173			if !models.ValidRoles()[req.Role] {
174				return echo.NewHTTPError(http.StatusBadRequest,
175					"invalid role; choose one of: learner, procurement_specialist, approver, finance_analyst, content_moderator")
176			}
177			assignedRole = req.Role
178		}
179	
180		existing, err := h.userRepo.FindByUsername(ctx, req.Username)
181		if err != nil {
182			log.Printf("[auth] find user error: %v", err)
183			return echo.NewHTTPError(http.StatusInternalServerError, "registration temporarily unavailable")
184		}
185		if existing != nil {
186			return echo.NewHTTPError(http.StatusConflict, "username already taken")
187		}
188	
189		hashedPassword, err := crypto.HashPassword(req.Password)
190		if err != nil {
191			log.Printf("[auth] hash error: %v", err)
192			return echo.NewHTTPError(http.StatusInternalServerError, "registration temporarily unavailable")
193		}
194	
195		user, err := h.userRepo.CreateUser(ctx, req.Username, req.Email, hashedPassword,
196			req.DisplayName, req.JobFamily, req.Department, req.CostCenter)
197		if err != nil {
198			if strings.Contains(err.Error(), "duplicate key") {
199				if strings.Contains(err.Error(), "email") {
200					return echo.NewHTTPError(http.StatusConflict, "email already registered")
201				}
202				return echo.NewHTTPError(http.StatusConflict, "username already taken")
203			}
204			log.Printf("[auth] create user error: %v", err)
205			return echo.NewHTTPError(http.StatusInternalServerError, "registration temporarily unavailable")
206		}
207	
208		if err := h.userRepo.AssignRole(ctx, user.ID, assignedRole, nil); err != nil {
209			log.Printf("[auth] assign role error user=%d role=%s: %v", user.ID, assignedRole, err)
210			return echo.NewHTTPError(http.StatusInternalServerError, "registration succeeded but role assignment failed; contact an administrator")
211		}
212	
213		uwr, err := h.userRepo.GetUserWithRoles(ctx, user.ID)
214		if err != nil {
215			uwr = &models.UserWithRoles{User: *user}
216		}
217	
218		msg := fmt.Sprintf("Registration successful. You have been assigned the %s role.",
219			strings.ReplaceAll(assignedRole, "_", " "))
220		if isFirstUser {
221			msg = "Welcome! As the first user, you have been assigned the system admin role."
222		}
223	
224		return c.JSON(http.StatusCreated, models.RegisterResponse{
225			Message: msg,
226			User:    uwr,
227		})
228	}
229	
230	// GET /api/admin/users  (admin only)
231	func (h *AuthHandler) ListUsers(c echo.Context) error {
232		users, err := h.userRepo.GetAllUsers(c.Request().Context())
233		if err != nil {
234			log.Printf("[admin] list users error: %v", err)
235			return echo.NewHTTPError(http.StatusInternalServerError, "failed to retrieve users")
236		}
237		return c.JSON(http.StatusOK, users)
238	}
239	
240	// POST /api/admin/users/assign-role  (admin only)
241	func (h *AuthHandler) AssignRole(c echo.Context) error {
242		var req models.AssignRoleRequest
243		if err := c.Bind(&req); err != nil {
244			return echo.NewHTTPError(http.StatusBadRequest, "invalid request body")
245		}
246		if req.UserID == 0 || req.Role == "" {
247			return echo.NewHTTPError(http.StatusBadRequest, "user_id and role are required")
248		}
249	
250		if !models.AllRoles()[req.Role] {
251			return echo.NewHTTPError(http.StatusBadRequest, "invalid role name")
252		}
253	
254		adminID := c.Get("user_id").(int)
255		if err := h.userRepo.AssignRole(c.Request().Context(), req.UserID, req.Role, &adminID); err != nil {
