162	// sendWebhook sends export data to a LAN-based webhook with retry/compensation.
163	func (s *ExportSinkService) sendWebhook(ctx context.Context, cfg ExportConfig, exportType string, data []byte) error {
164		payload := map[string]interface{}{
165			"export_type": exportType,
166			"timestamp":   time.Now().UTC().Format(time.RFC3339),
167			"data_base64": data,
168			"format":      "csv",
169		}
170	
171		body, err := json.Marshal(payload)
172		if err != nil {
173			return fmt.Errorf("failed to marshal webhook payload: %w", err)
174		}
175	
176		var lastErr error
177		for attempt := 1; attempt <= cfg.MaxRetries; attempt++ {
178			if ctx.Err() != nil {
179				return fmt.Errorf("context cancelled during webhook retry: %w", ctx.Err())
180			}
181	
182			req, err := http.NewRequestWithContext(ctx, http.MethodPost, cfg.WebhookURL, bytes.NewReader(body))
183			if err != nil {
184				return fmt.Errorf("failed to create webhook request: %w", err)
185			}
186			req.Header.Set("Content-Type", "application/json")
187			req.Header.Set("X-Export-Type", exportType)
188	
189			client := &http.Client{Timeout: 30 * time.Second}
190			resp, err := client.Do(req)
191			if err != nil {
192				lastErr = fmt.Errorf("attempt %d/%d: %w", attempt, cfg.MaxRetries, err)
193				log.Printf("[export-sink] webhook attempt %d/%d failed: %v", attempt, cfg.MaxRetries, err)
194				if attempt < cfg.MaxRetries {
195					time.Sleep(time.Duration(cfg.RetryDelaySecs) * time.Second)
196				}
197				continue
198			}
199	
200			resp.Body.Close()
201	
202			if resp.StatusCode >= 200 && resp.StatusCode < 300 {
203				log.Printf("[export-sink] webhook succeeded on attempt %d/%d", attempt, cfg.MaxRetries)
204				return nil
205			}
206	
207			lastErr = fmt.Errorf("attempt %d/%d: HTTP %d", attempt, cfg.MaxRetries, resp.StatusCode)
208			log.Printf("[export-sink] webhook attempt %d/%d returned HTTP %d", attempt, cfg.MaxRetries, resp.StatusCode)
209			if attempt < cfg.MaxRetries {
210				time.Sleep(time.Duration(cfg.RetryDelaySecs) * time.Second)
211			}
212		}
213	
214		// Compensation: write to file-drop as fallback if webhook fails
215		fileFallbackDir, _ := s.configSvc.GetConfig("export.file_drop_dir")
216		if fileFallbackDir != "" {
217			log.Printf("[export-sink] webhook failed after %d retries; compensating with file-drop fallback", cfg.MaxRetries)
218			if err := s.writeFileDrop(fileFallbackDir, exportType+"_webhook_fallback", data); err != nil {
219				log.Printf("[export-sink] fallback file-drop also failed: %v", err)
220			}
221		}
222	
223		return fmt.Errorf("webhook failed after %d retries: %w", cfg.MaxRetries, lastErr)
224	}
