26	// CompareStatement compares a vendor's statement total against ledger entries.
27	// If variance < threshold -> PENDING_APPROVAL (auto-suggest write-off).
28	// If variance >= threshold -> MANUAL_INVESTIGATION.
29	func (s *ReconciliationService) CompareStatement(ctx context.Context, req models.CompareStatementRequest) (*models.CompareStatementResponse, error) {
30		if req.VendorID <= 0 {
31			return nil, fmt.Errorf("vendor_id is required")
32		}
33	
34		// Sum AR entries for the vendor in the period
35		ledgerTotal, err := s.procRepo.SumLedgerByVendor(ctx, req.VendorID, "AR", req.PeriodStart, req.PeriodEnd)
36		if err != nil {
37			return nil, fmt.Errorf("failed to sum ledger: %w", err)
38		}
39	
40		variance := req.StatementTotal - ledgerTotal
41		variancePct := 0.0
42		if ledgerTotal != 0 {
43			variancePct = math.Round((variance/ledgerTotal)*10000) / 100
44		}
45	
46		// Get write-off threshold from config (default $5.00)
47		threshold := 5.00
48		if val, ok := s.configSvc.GetConfig("variance.auto_writeoff_threshold"); ok {
49			fmt.Sscanf(val, "%f", &threshold)
50		}
51	
52		absVariance := math.Abs(variance)
53		autoWriteoff := absVariance < threshold && absVariance > 0
54		suggestedState := "matched"
55		if absVariance > 0 {
56			if absVariance < threshold {
57				suggestedState = "pending_approval"
58			} else {
59				suggestedState = "manual_investigation"
60			}
61		}
62	
63		return &models.CompareStatementResponse{
64			VendorID:       req.VendorID,
65			StatementTotal: req.StatementTotal,
66			LedgerTotal:    ledgerTotal,
67			Variance:       math.Round(variance*100) / 100,
68			VariancePct:    variancePct,
69			AutoWriteoff:   autoWriteoff,
70			SuggestedState: suggestedState,
71		}, nil
72	}
