74	// MatchInvoice matches an invoice to an order, computing variance and auto-classifying.
75	func (s *ReconciliationService) MatchInvoice(ctx context.Context, invoiceID, orderID, userID int) error {
76		order, err := s.procRepo.GetOrderByID(ctx, orderID)
77		if err != nil || order == nil {
78			return fmt.Errorf("order not found")
79		}
