96	// TransitionSettlement validates and executes settlement status transitions.
97	// Valid transitions:
98	//
99	//	open -> matched
100	//	matched -> variance_pending
101	//	variance_pending -> writeoff_suggested
102	//	writeoff_suggested -> writeoff_approved (requires Finance approval)
103	//	writeoff_approved -> settled
104	//	any open state -> disputed
105	//	matched -> settled (no variance)
106	func (s *ReconciliationService) TransitionSettlement(ctx context.Context, req models.SettlementTransitionRequest, userID int) error {
107		settlement, err := s.procRepo.GetSettlementByID(ctx, req.SettlementID)
108		if err != nil || settlement == nil {
109			return fmt.Errorf("settlement not found")
110		}
111	
112		currentStatus := settlement.Status
113		var newStatus string
114	
115		switch req.Action {
116		case "match":
117			if currentStatus != "open" {
118				return fmt.Errorf("invalid transition: cannot match from status %s", currentStatus)
119			}
120			newStatus = "matched"
121	
122		case "flag_variance":
123			if currentStatus != "matched" {
124				return fmt.Errorf("invalid transition: cannot flag variance from status %s", currentStatus)
125			}
126			newStatus = "variance_pending"
127	
128		case "suggest_writeoff":
129			if currentStatus != "variance_pending" {
130				return fmt.Errorf("invalid transition: cannot suggest write-off from status %s", currentStatus)
131			}
132			// Validate variance is below threshold for auto-suggest
133			threshold := 5.00
134			if val, ok := s.configSvc.GetConfig("variance.auto_writeoff_threshold"); ok {
135				fmt.Sscanf(val, "%f", &threshold)
136			}
137			if math.Abs(settlement.VarianceAmount) >= threshold {
138				return fmt.Errorf("variance $%.2f exceeds auto write-off threshold $%.2f; requires manual investigation", math.Abs(settlement.VarianceAmount), threshold)
139			}
140			newStatus = "writeoff_suggested"
141	
142		case "approve_writeoff":
143			if currentStatus != "writeoff_suggested" {
144				return fmt.Errorf("invalid transition: cannot approve write-off from status %s", currentStatus)
145			}
146			newStatus = "writeoff_approved"
147	
148		case "settle":
149			if currentStatus != "matched" && currentStatus != "writeoff_approved" {
150				return fmt.Errorf("invalid transition: cannot settle from status %s", currentStatus)
151			}
152			newStatus = "settled"
153	
154		case "dispute":
155			if currentStatus == "settled" || currentStatus == "disputed" {
156				return fmt.Errorf("invalid transition: cannot dispute from status %s", currentStatus)
157			}
158			newStatus = "disputed"
159	
160		default:
161			return fmt.Errorf("unknown action: %s", req.Action)
162		}
163	
164		return s.procRepo.UpdateSettlement(ctx, req.SettlementID, newStatus, &userID, req.Notes)
165	}
166	
167	// TransitionDispute validates and executes dispute state transitions.
168	// The DB trigger trg_dispute_state_machine also enforces this, providing defense-in-depth.
169	//
170	// Valid transitions:
171	//
172	//	created -> evidence_uploaded
173	//	evidence_uploaded -> under_review
174	//	under_review -> arbitration
175	//	arbitration -> resolved_hidden | resolved_disclaimer | resolved_restored | rejected
176	func (s *ReconciliationService) TransitionDispute(ctx context.Context, req models.DisputeTransitionRequest, userID int) error {
177		dispute, err := s.procRepo.GetDisputeByID(ctx, req.DisputeID)
178		if err != nil || dispute == nil {
179			return fmt.Errorf("dispute not found")
180		}
181	
182		currentStatus := dispute.Status
183		var newStatus string
184		updates := make(map[string]interface{})
185	
186		switch req.Action {
187		case "upload_evidence":
188			if currentStatus != "created" {
189				return fmt.Errorf("invalid transition: cannot upload evidence from status %s (must be 'created')", currentStatus)
190			}
191			if len(req.EvidenceURLs) == 0 {
192				return fmt.Errorf("at least one evidence URL is required")
193			}
194			newStatus = "evidence_uploaded"
195			updates["evidence_urls"] = req.EvidenceURLs
196	
197			// Encrypt evidence metadata at rest if provided
198			if req.EvidenceMetadata != "" {
199				encMeta, err := crypto.EncryptString(req.EvidenceMetadata)
200				if err != nil {
201					log.Printf("[reconciliation] evidence metadata encryption error: %v", err)
202					return fmt.Errorf("failed to encrypt evidence metadata")
203				}
204				updates["evidence_metadata_enc"] = encMeta
205			}
206	
207		case "start_review":
208			if currentStatus != "evidence_uploaded" {
209				return fmt.Errorf("invalid transition: cannot start review from status %s (must be 'evidence_uploaded')", currentStatus)
210			}
211			newStatus = "under_review"
212	
213		case "respond":
214			if currentStatus != "evidence_uploaded" && currentStatus != "under_review" {
215				return fmt.Errorf("merchant can only respond during evidence_uploaded or under_review phase")
216			}
217			if req.MerchantResponse == "" {
218				return fmt.Errorf("merchant_response is required")
219			}
220			// Merchant response doesn't change state, just records the response
221			updates["merchant_response"] = req.MerchantResponse
222			newStatus = currentStatus // no state change for response
223	
224		case "escalate_arbitration":
225			if currentStatus != "under_review" {
226				return fmt.Errorf("invalid transition: cannot escalate to arbitration from status %s (must be 'under_review')", currentStatus)
227			}
228			newStatus = "arbitration"
229	
230		case "arbitrate":
231			if currentStatus != "arbitration" {
232				return fmt.Errorf("invalid transition: cannot arbitrate from status %s (must be 'arbitration')", currentStatus)
233			}
234			outcome := req.ArbitrationOutcome
235			if outcome != "hide" && outcome != "disclaimer" && outcome != "restore" {
236				return fmt.Errorf("arbitration_outcome must be 'hide', 'disclaimer', or 'restore'")
237			}
238	
239			switch outcome {
240			case "hide":
241				newStatus = "resolved_hidden"
242			case "disclaimer":
243				newStatus = "resolved_disclaimer"
244			case "restore":
245				newStatus = "resolved_restored"
246			}
247	
248			updates["arbitration_notes"] = req.ArbitrationNotes
249			updates["arbitration_outcome"] = outcome
250			updates["arbitrated_by"] = userID
251	
252		case "reject":
253			if currentStatus != "arbitration" {
254				return fmt.Errorf("invalid transition: cannot reject from status %s (must be 'arbitration')", currentStatus)
255			}
256			newStatus = "rejected"
257			updates["arbitration_notes"] = req.ArbitrationNotes
258			updates["arbitrated_by"] = userID
259	
260		default:
261			return fmt.Errorf("unknown dispute action: %s", req.Action)
262		}
263	
264		// If merchant response (no state change), handle separately
265		if req.Action == "respond" {
266			return s.procRepo.TransitionDispute(ctx, req.DisputeID, currentStatus, updates)
267		}
268	
269		err = s.procRepo.TransitionDispute(ctx, req.DisputeID, newStatus, updates)
270		if err != nil {
271			return fmt.Errorf("transition failed: %w", err)
272		}
273	
274		// Apply review status change based on arbitration outcome
275		if req.Action == "arbitrate" || req.Action == "reject" {
276			return s.applyArbitrationOutcome(ctx, dispute.ReviewID, newStatus, req.ArbitrationNotes)
277		}
278	
279		return nil
280	}
281	
282	// applyArbitrationOutcome updates the vendor review based on dispute resolution.
283	func (s *ReconciliationService) applyArbitrationOutcome(ctx context.Context, reviewID int, disputeStatus, notes string) error {
284		switch disputeStatus {
285		case "resolved_hidden":
286			return s.procRepo.UpdateReviewStatus(ctx, reviewID, "hidden", "")
287		case "resolved_disclaimer":
288			disclaimer := "This review is subject to a resolved dispute."
289			if notes != "" {
290				disclaimer = notes
291			}
292			return s.procRepo.UpdateReviewStatus(ctx, reviewID, "disclaimer", disclaimer)
293		case "resolved_restored":
294			return s.procRepo.UpdateReviewStatus(ctx, reviewID, "visible", "")
295		case "rejected":
296			// Dispute rejected = review stays visible
297			return s.procRepo.UpdateReviewStatus(ctx, reviewID, "visible", "")
298		}
299		return nil
300	}
