16	
17	// RecommendationWorker runs as a background goroutine, computing user-item
18	// similarity matrices and writing recommendations to the DB. It enforces the
19	// diversity control (no >40% from a single category) and job-family cold-start defaults.
20	type RecommendationWorker struct {
21		learningRepo *repository.LearningRepository
22		searchRepo   *repository.SearchRepository
23		configSvc    *ConfigService
24		maxCatPct    float64 // e.g., 0.40
25	}
26	
27	func NewRecommendationWorker(learningRepo *repository.LearningRepository, searchRepo *repository.SearchRepository, configSvc *ConfigService) *RecommendationWorker {
28		return &RecommendationWorker{
29			learningRepo: learningRepo,
30			searchRepo:   searchRepo,
31			configSvc:    configSvc,
32			maxCatPct:    0.40,
33		}
34	}
35	
36	// Start launches the nightly recommendation rebuild loop.
37	// It runs immediately once, then repeats on the given interval.
38	func (w *RecommendationWorker) Start(ctx context.Context, interval time.Duration) {
39		go func() {
40			// Run once on startup
41			w.run(ctx)
42	
43			ticker := time.NewTicker(interval)
44			defer ticker.Stop()
45			for {
46				select {
47				case <-ctx.Done():
48					log.Println("[rec-worker] shutting down")
49					return
50				case <-ticker.C:
51					w.run(ctx)
52				}
53			}
54		}()
55		log.Printf("[rec-worker] started with interval %s", interval)
56	}
57	
58	func (w *RecommendationWorker) run(ctx context.Context) {
59		start := time.Now()
60		log.Println("[rec-worker] starting recommendation computation...")
61	
62		// Reload max category percentage from config
63		if val, ok := w.configSvc.GetConfig("recommendation.max_category_pct"); ok {
64			var pct float64
65			if _, err := fmt.Sscanf(val, "%f", &pct); err == nil && pct > 0 && pct <= 100 {
66				w.maxCatPct = pct / 100.0
67			}
68		}
69	
70		userIDs, err := w.learningRepo.GetAllUserIDs(ctx)
71		if err != nil {
72			log.Printf("[rec-worker] failed to get user IDs: %v", err)
73			return
74		}
75	
76		allResources, err := w.learningRepo.GetAllPublishedResources(ctx)
77		if err != nil {
78			log.Printf("[rec-worker] failed to get resources: %v", err)
79			return
80		}
81	
82		// Build a global user-item interaction matrix
83		userVectors := make(map[int]map[int]float64)
84		for _, uid := range userIDs {
85			vec, err := w.learningRepo.GetUserEventVector(ctx, uid)
86			if err != nil {
87				continue
88			}
89			userVectors[uid] = vec
90		}
91	
92		batchID := uuid.New().String()
93	
94		for _, userID := range userIDs {
95			recs := w.computeForUser(ctx, userID, userVectors, allResources)
96	
97			// Apply diversity control
98			recs = w.applyDiversityControl(recs)
99	
100			// Write recommendations
101			for _, rec := range recs {
102				err := w.learningRepo.UpsertRecommendation(ctx,
103					rec.UserID, rec.ResourceID, rec.Score, rec.Reason, rec.CategoryID, batchID)
104				if err != nil {
105					log.Printf("[rec-worker] write error user=%d resource=%d: %v", rec.UserID, rec.ResourceID, err)
106				}
107			}
108	
109			// Clean old recommendations
110			_ = w.learningRepo.ClearOldRecommendations(ctx, userID, batchID)
111		}
112	
113		// Refresh archive materialized views (auto-generated by month and tag)
114		if w.searchRepo != nil {
115			if _, err := w.searchRepo.RefreshArchiveViews(ctx); err != nil {
116				log.Printf("[rec-worker] archive refresh error: %v", err)
117			} else {
118				log.Println("[rec-worker] archive materialized views refreshed")
119			}
120		}
121	
122		log.Printf("[rec-worker] completed in %s for %d users", time.Since(start), len(userIDs))
123	}
124	
125	type scoredResource struct {
126		ResourceID int
127		CategoryID *int
128		Score      float64
129		Reason     string
130	}
131	
132	func (w *RecommendationWorker) computeForUser(ctx context.Context, userID int,
133		userVectors map[int]map[int]float64, allResources []models.Resource) []models.Recommendation {
134	
135		myVector := userVectors[userID]
136		hasInteractions := len(myVector) > 0
137	
138		var scored []scoredResource
139	
140		if !hasInteractions {
141			// Cold-start: recommend by job family and global popularity
142			scored = w.coldStartDefaults(ctx, userID, allResources)
143		} else {
144			// Collaborative filtering: find similar users and recommend their items
145			scored = w.collaborativeFilter(userID, myVector, userVectors, allResources)
146		}
147	
148		// Convert to Recommendation model
149		recs := make([]models.Recommendation, 0, len(scored))
150		for _, s := range scored {
151			recs = append(recs, models.Recommendation{
152				UserID:     userID,
153				ResourceID: s.ResourceID,
154				Score:      s.Score,
155				Reason:     s.Reason,
156				CategoryID: s.CategoryID,
157			})
158		}
159		return recs
160	}
161	
162	// coldStartDefaults generates recommendations for users with no interaction history.
163	// Uses job family matching and global popularity as signals.
164	func (w *RecommendationWorker) coldStartDefaults(ctx context.Context, userID int,
165		allResources []models.Resource) []scoredResource {
166	
167		var scored []scoredResource
168	
169		jobFamily, _ := w.learningRepo.GetUserJobFamily(ctx, userID)
170	
171		if jobFamily != "" {
172			// Get resources matching the user's job family
173			jfResources, err := w.learningRepo.GetResourcesByJobFamily(ctx, jobFamily)
174			if err == nil {
175				for i, r := range jfResources {
176					scored = append(scored, scoredResource{
177						ResourceID: r.ID,
178						CategoryID: r.CategoryID,
179						Score:      100.0 - float64(i)*2.0,
180						Reason:     "job_family",
181					})
182				}
183			}
184		}
185	
186		// Fill remaining slots with globally popular resources
187		seen := make(map[int]bool)
188		for _, s := range scored {
189			seen[s.ResourceID] = true
190		}
191		for _, r := range allResources {
192			if seen[r.ID] {
193				continue
194			}
195			scored = append(scored, scoredResource{
196				ResourceID: r.ID,
197				CategoryID: r.CategoryID,
198				Score:      r.PopularityScore * 0.5,
199				Reason:     "cold_start",
200			})
201			if len(scored) >= 30 {
202				break
203			}
204		}
205	
206		// Sort by score descending
207		sort.Slice(scored, func(i, j int) bool {
208			return scored[i].Score > scored[j].Score
209		})
210	
211		if len(scored) > 20 {
212			scored = scored[:20]
213		}
214		return scored
215	}
216	
217	// collaborativeFilter computes user-user similarity via cosine similarity
218	// on the interaction vectors, then recommends items that similar users consumed
219	// but the target user hasn't.
220	func (w *RecommendationWorker) collaborativeFilter(userID int,
221		myVector map[int]float64, userVectors map[int]map[int]float64,
222		allResources []models.Resource) []scoredResource {
223	
224		// Compute similarity with every other user
225		type userSim struct {
226			uid int
227			sim float64
228		}
229		var similarities []userSim
230	
231		for otherUID, otherVec := range userVectors {
232			if otherUID == userID {
233				continue
234			}
235			sim := cosineSimilarity(myVector, otherVec)
236			if sim > 0.01 {
237				similarities = append(similarities, userSim{otherUID, sim})
238			}
239		}
240	
241		// Sort by similarity descending, take top-K neighbors
242		sort.Slice(similarities, func(i, j int) bool {
243			return similarities[i].sim > similarities[j].sim
244		})
245		k := 10
246		if len(similarities) < k {
247			k = len(similarities)
248		}
249		neighbors := similarities[:k]
250	
251		// Score resources from neighbors that the user hasn't consumed
252		resourceScores := make(map[int]float64)
253		resourceReasons := make(map[int]string)
254		for _, neighbor := range neighbors {
255			neighborVec := userVectors[neighbor.uid]
256			for rid, count := range neighborVec {
257				if _, consumed := myVector[rid]; consumed {
258					continue
259				}
260				resourceScores[rid] += neighbor.sim * count
261				resourceReasons[rid] = "similar_users"
262			}
263		}
264	
265		// Also boost resources that share tags with consumed resources
266		for rid := range myVector {
267			// Find resources in the same category
268			for _, res := range allResources {
269				if _, consumed := myVector[res.ID]; consumed {
270					continue
271				}
272				// Simple tag-match heuristic: same category gets a boost
273				if res.CategoryID != nil {
274					for _, consumed := range allResources {
275						if consumed.ID == rid && consumed.CategoryID != nil && *consumed.CategoryID == *res.CategoryID {
276							resourceScores[res.ID] += 5.0
277							if resourceReasons[res.ID] == "" {
278								resourceReasons[res.ID] = "tag_match"
279							}
280						}
281					}
282				}
283			}
284		}
285	
286		// Build resource lookup for category info
287		resMap := make(map[int]*models.Resource)
288		for i := range allResources {
289			resMap[allResources[i].ID] = &allResources[i]
290		}
291	
292		var scored []scoredResource
293		for rid, score := range resourceScores {
294			var catID *int
295			if res, ok := resMap[rid]; ok {
296				catID = res.CategoryID
297			}
298			scored = append(scored, scoredResource{
299				ResourceID: rid,
300				CategoryID: catID,
301				Score:      score,
302				Reason:     resourceReasons[rid],
303			})
304		}
305	
306		// Add popular items the user hasn't seen to fill gaps
307		seen := make(map[int]bool)
308		for _, s := range scored {
309			seen[s.ResourceID] = true
310		}
311		for rid := range myVector {
312			seen[rid] = true
313		}
314		for _, r := range allResources {
315			if seen[r.ID] {
316				continue
317			}
318			scored = append(scored, scoredResource{
319				ResourceID: r.ID,
320				CategoryID: r.CategoryID,
321				Score:      r.PopularityScore * 0.3,
322				Reason:     "popular",
323			})
324			if len(scored) >= 40 {
325				break
326			}
327		}
328	
329		sort.Slice(scored, func(i, j int) bool {
330			return scored[i].Score > scored[j].Score
331		})
332	
333		if len(scored) > 20 {
334			scored = scored[:20]
335		}
336		return scored
337	}
338	
339	// applyDiversityControl ensures no more than maxCatPct of the final recommendation
340	// set comes from a single category. It iterates through the sorted list, skips items
341	// that would exceed the category quota, and re-checks the quota when backfilling
342	// from deferred items to guarantee the cap is never exceeded.
343	func (w *RecommendationWorker) applyDiversityControl(recs []models.Recommendation) []models.Recommendation {
344		if len(recs) == 0 {
345			return recs
346		}
347	
348		targetSize := len(recs)
349		maxPerCat := int(math.Ceil(float64(targetSize) * w.maxCatPct))
350		if maxPerCat < 1 {
351			maxPerCat = 1
352		}
353	
354		catCounts := make(map[int]int)
355		var filtered []models.Recommendation
356		var deferred []models.Recommendation
357	
358		for _, rec := range recs {
359			catKey := 0
360			if rec.CategoryID != nil {
361				catKey = *rec.CategoryID
362			}
363	
364			if catCounts[catKey] < maxPerCat {
365				catCounts[catKey]++
366				filtered = append(filtered, rec)
367			} else {
368				deferred = append(deferred, rec)
369			}
370		}
371	
372		// Recalculate maxPerCat based on the final target size (which stays the same
373		// as the original length). Fill remaining slots from deferred, but re-check
374		// the category quota to guarantee the cap is never exceeded.
375		for _, rec := range deferred {
376			if len(filtered) >= targetSize {
377				break
378			}
379	
380			catKey := 0
381			if rec.CategoryID != nil {
382				catKey = *rec.CategoryID
383			}
384	
385			if catCounts[catKey] < maxPerCat {
386				catCounts[catKey]++
387				filtered = append(filtered, rec)
388			}
389			// If this deferred item also exceeds the cap, skip it entirely
390		}
391	
392		return filtered
393	}
394	
395	// cosineSimilarity computes the cosine similarity between two sparse vectors.
396	func cosineSimilarity(a, b map[int]float64) float64 {
397		var dot, normA, normB float64
398		for key, va := range a {
399			normA += va * va
400			if vb, ok := b[key]; ok {
401				dot += va * vb
402			}
403		}
404		for _, vb := range b {
405			normB += vb * vb
406		}
407		if normA == 0 || normB == 0 {
408			return 0
409		}
410		return dot / (math.Sqrt(normA) * math.Sqrt(normB))
411	}
