1	package services
2	
3	import (
4		"bytes"
5		"context"
6		"encoding/csv"
7		"encoding/json"
8		"fmt"
9		"log"
10		"net/http"
11		"os"
12		"path/filepath"
13		"time"
14	
15		"wlpr-portal/internal/models"
16	)
17	
18	// ExportSinkService handles offline finance export to file-drop directories
19	// and LAN-based webhooks with retry and compensation logic.
20	type ExportSinkService struct {
21		configSvc *ConfigService
22	}
23	
24	func NewExportSinkService(configSvc *ConfigService) *ExportSinkService {
25		return &ExportSinkService{configSvc: configSvc}
26	}
27	
28	// ExportConfig holds resolved export sink configuration.
29	type ExportConfig struct {
30		FileDropDir    string
31		WebhookURL     string
32		MaxRetries     int
33		RetryDelaySecs int
34	}
35	
36	// getExportConfig resolves export sink configuration from the config service.
37	func (s *ExportSinkService) getExportConfig() ExportConfig {
38		cfg := ExportConfig{
39			MaxRetries:     3,
40			RetryDelaySecs: 5,
41		}
42	
43		if dir, ok := s.configSvc.GetConfig("export.file_drop_dir"); ok && dir != "" {
44			cfg.FileDropDir = dir
45		}
46		if url, ok := s.configSvc.GetConfig("export.webhook_url"); ok && url != "" {
47			cfg.WebhookURL = url
48		}
49		if v, ok := s.configSvc.GetConfig("export.max_retries"); ok {
50			var n int
51			if _, err := fmt.Sscanf(v, "%d", &n); err == nil && n > 0 {
52				cfg.MaxRetries = n
53			}
54		}
55		if v, ok := s.configSvc.GetConfig("export.retry_delay_seconds"); ok {
56			var n int
57			if _, err := fmt.Sscanf(v, "%d", &n); err == nil && n > 0 {
58				cfg.RetryDelaySecs = n
59			}
60		}
61		return cfg
62	}
63	
64	// ExportLedgerToSinks exports ledger entries to configured sinks (file-drop and/or webhook).
65	// Returns nil if no sinks are configured (browser CSV download is still available).
66	func (s *ExportSinkService) ExportLedgerToSinks(ctx context.Context, entries []models.LedgerEntry) error {
67		cfg := s.getExportConfig()
68	
69		if cfg.FileDropDir == "" && cfg.WebhookURL == "" {
70			return nil // No sinks configured; browser download only
71		}
72	
73		csvData, err := ledgerToCSV(entries)
74		if err != nil {
75			return fmt.Errorf("failed to generate CSV: %w", err)
76		}
77	
78		var errs []error
79	
80		if cfg.FileDropDir != "" {
81			if err := s.writeFileDrop(cfg.FileDropDir, "ledger_export", csvData); err != nil {
82				log.Printf("[export-sink] file-drop error: %v", err)
83				errs = append(errs, fmt.Errorf("file-drop: %w", err))
84			} else {
85				log.Printf("[export-sink] ledger exported to file-drop: %s", cfg.FileDropDir)
86			}
87		}
88	
89		if cfg.WebhookURL != "" {
90			if err := s.sendWebhook(ctx, cfg, "ledger_export", csvData); err != nil {
91				log.Printf("[export-sink] webhook error: %v", err)
92				errs = append(errs, fmt.Errorf("webhook: %w", err))
93			} else {
94				log.Printf("[export-sink] ledger exported via webhook: %s", cfg.WebhookURL)
95			}
96		}
97	
98		if len(errs) > 0 {
99			return fmt.Errorf("export sink errors: %v", errs)
100		}
101		return nil
102	}
103	
104	// ExportSettlementsToSinks exports settlements to configured sinks.
105	func (s *ExportSinkService) ExportSettlementsToSinks(ctx context.Context, settlements []models.Settlement) error {
106		cfg := s.getExportConfig()
107	
108		if cfg.FileDropDir == "" && cfg.WebhookURL == "" {
109			return nil
110		}
111	
112		csvData, err := settlementsToCSV(settlements)
113		if err != nil {
114			return fmt.Errorf("failed to generate CSV: %w", err)
115		}
116	
117		var errs []error
118	
119		if cfg.FileDropDir != "" {
120			if err := s.writeFileDrop(cfg.FileDropDir, "settlements_export", csvData); err != nil {
121				log.Printf("[export-sink] file-drop error: %v", err)
122				errs = append(errs, fmt.Errorf("file-drop: %w", err))
123			} else {
124				log.Printf("[export-sink] settlements exported to file-drop: %s", cfg.FileDropDir)
125			}
126		}
127	
128		if cfg.WebhookURL != "" {
129			if err := s.sendWebhook(ctx, cfg, "settlements_export", csvData); err != nil {
130				log.Printf("[export-sink] webhook error: %v", err)
131				errs = append(errs, fmt.Errorf("webhook: %w", err))
132			} else {
133				log.Printf("[export-sink] settlements exported via webhook: %s", cfg.WebhookURL)
134			}
135		}
136	
137		if len(errs) > 0 {
138			return fmt.Errorf("export sink errors: %v", errs)
139		}
140		return nil
141	}
142	
143	// writeFileDrop writes a CSV file to the configured file-drop directory.
144	func (s *ExportSinkService) writeFileDrop(dir, prefix string, data []byte) error {
145		if err := os.MkdirAll(dir, 0750); err != nil {
146			return fmt.Errorf("failed to create export directory %s: %w", dir, err)
147		}
148	
149		timestamp := time.Now().Format("20060102_150405")
150		filename := fmt.Sprintf("%s_%s.csv", prefix, timestamp)
151		filePath := filepath.Join(dir, filename)
152	
153		if err := os.WriteFile(filePath, data, 0640); err != nil {
154			return fmt.Errorf("failed to write export file %s: %w", filePath, err)
155		}
156	
157		log.Printf("[export-sink] file written: %s (%d bytes)", filePath, len(data))
158		return nil
159	}
160	
161	// sendWebhook sends export data to a LAN-based webhook with retry/compensation.
162	func (s *ExportSinkService) sendWebhook(ctx context.Context, cfg ExportConfig, exportType string, data []byte) error {
163		payload := map[string]interface{}{
164			"export_type": exportType,
165			"timestamp":   time.Now().UTC().Format(time.RFC3339),
166			"data_base64": data,
167			"format":      "csv",
168		}
169	
170		body, err := json.Marshal(payload)
171		if err != nil {
172			return fmt.Errorf("failed to marshal webhook payload: %w", err)
173		}
174	
175		var lastErr error
176		for attempt := 1; attempt <= cfg.MaxRetries; attempt++ {
177			if ctx.Err() != nil {
178				return fmt.Errorf("context cancelled during webhook retry: %w", ctx.Err())
179			}
180	
181			req, err := http.NewRequestWithContext(ctx, http.MethodPost, cfg.WebhookURL, bytes.NewReader(body))
182			if err != nil {
183				return fmt.Errorf("failed to create webhook request: %w", err)
184			}
185			req.Header.Set("Content-Type", "application/json")
186			req.Header.Set("X-Export-Type", exportType)
187	
188			client := &http.Client{Timeout: 30 * time.Second}
189			resp, err := client.Do(req)
190			if err != nil {
191				lastErr = fmt.Errorf("attempt %d/%d: %w", attempt, cfg.MaxRetries, err)
192				log.Printf("[export-sink] webhook attempt %d/%d failed: %v", attempt, cfg.MaxRetries, err)
193				if attempt < cfg.MaxRetries {
194					time.Sleep(time.Duration(cfg.RetryDelaySecs) * time.Second)
195				}
196				continue
197			}
198	
199			resp.Body.Close()
200	
201			if resp.StatusCode >= 200 && resp.StatusCode < 300 {
202				log.Printf("[export-sink] webhook succeeded on attempt %d/%d", attempt, cfg.MaxRetries)
203				return nil
204			}
205	
206			lastErr = fmt.Errorf("attempt %d/%d: HTTP %d", attempt, cfg.MaxRetries, resp.StatusCode)
207			log.Printf("[export-sink] webhook attempt %d/%d returned HTTP %d", attempt, cfg.MaxRetries, resp.StatusCode)
208			if attempt < cfg.MaxRetries {
209				time.Sleep(time.Duration(cfg.RetryDelaySecs) * time.Second)
210			}
211		}
212	
213		// Compensation: write to file-drop as fallback if webhook fails
214		fileFallbackDir, _ := s.configSvc.GetConfig("export.file_drop_dir")
215		if fileFallbackDir != "" {
216			log.Printf("[export-sink] webhook failed after %d retries; compensating with file-drop fallback", cfg.MaxRetries)
217			if err := s.writeFileDrop(fileFallbackDir, exportType+"_webhook_fallback", data); err != nil {
218				log.Printf("[export-sink] fallback file-drop also failed: %v", err)
219			}
220		}
221	
222		return fmt.Errorf("webhook failed after %d retries: %w", cfg.MaxRetries, lastErr)
223	}
224	
225	// ledgerToCSV converts ledger entries to CSV bytes.
226	func ledgerToCSV(entries []models.LedgerEntry) ([]byte, error) {
227		var buf bytes.Buffer
228		writer := csv.NewWriter(&buf)
229	
230		_ = writer.Write([]string{
231			"Entry ID", "Type", "Reference Type", "Reference ID",
232			"Vendor ID", "Vendor Name", "Amount", "Currency",
233			"Department", "Cost Center", "Description", "Posted At",
234		})
235	
236		for _, e := range entries {
237			dept, cc, desc := "", "", ""
238			if e.Department != nil {
239				dept = *e.Department
240			}
241			if e.CostCenter != nil {
242				cc = *e.CostCenter
243			}
244			if e.Description != nil {
245				desc = *e.Description
246			}
247			_ = writer.Write([]string{
248				fmt.Sprintf("%d", e.ID), e.EntryType, e.ReferenceType,
249				fmt.Sprintf("%d", e.ReferenceID), fmt.Sprintf("%d", e.VendorID),
250				e.VendorName, fmt.Sprintf("%.2f", e.Amount), e.Currency,
251				dept, cc, desc, e.PostedAt.Format("2006-01-02 15:04:05"),
252			})
253		}
254	
255		writer.Flush()
256		if err := writer.Error(); err != nil {
257			return nil, err
258		}
259		return buf.Bytes(), nil
260	}
261	
262	// settlementsToCSV converts settlements to CSV bytes.
263	func settlementsToCSV(settlements []models.Settlement) ([]byte, error) {
264		var buf bytes.Buffer
265		writer := csv.NewWriter(&buf)
266	
267		_ = writer.Write([]string{
268			"Settlement ID", "Vendor ID", "Vendor Name", "Status",
269			"AR Total", "AP Total", "Net Amount", "Variance",
270			"Write-off", "Department", "Cost Center",
271			"Period Start", "Period End",
272		})
273	
274		for _, s := range settlements {
275			dept, cc, ps, pe := "", "", "", ""
276			if s.Department != nil {
277				dept = *s.Department
278			}
279			if s.CostCenter != nil {
280				cc = *s.CostCenter
281			}
282			if s.PeriodStart != nil {
283				ps = *s.PeriodStart
284			}
285			if s.PeriodEnd != nil {
286				pe = *s.PeriodEnd
287			}
288			_ = writer.Write([]string{
289				fmt.Sprintf("%d", s.ID), fmt.Sprintf("%d", s.VendorID),
290				s.VendorName, s.Status,
291				fmt.Sprintf("%.2f", s.ARTotal), fmt.Sprintf("%.2f", s.APTotal),
292				fmt.Sprintf("%.2f", s.NetAmount), fmt.Sprintf("%.2f", s.VarianceAmount),
293				fmt.Sprintf("%.2f", s.WriteoffAmount),
294				dept, cc, ps, pe,
295			})
296		}
297	
298		writer.Flush()
299		if err := writer.Error(); err != nil {
300			return nil, err
301		}
302		return buf.Bytes(), nil
303	}
