1	package middleware
2	
3	import (
4		"fmt"
5		"net/http"
6		"strings"
7		"time"
8	
9		"wlpr-portal/internal/services"
10		"wlpr-portal/pkg/jwt"
11	
12		"github.com/labstack/echo/v4"
13	)
14	
15	type AuthMiddleware struct {
16		authService   *services.AuthService
17		configService *services.ConfigService
18	}
19	
20	func NewAuthMiddleware(authService *services.AuthService, configService *services.ConfigService) *AuthMiddleware {
21		return &AuthMiddleware{
22			authService:   authService,
23			configService: configService,
24		}
25	}
26	
27	// RequireAuth validates the JWT, checks session validity (idle/max), and injects claims into context.
28	func (m *AuthMiddleware) RequireAuth() echo.MiddlewareFunc {
29		return func(next echo.HandlerFunc) echo.HandlerFunc {
30			return func(c echo.Context) error {
31				authHeader := c.Request().Header.Get("Authorization")
32				if authHeader == "" {
33					return echo.NewHTTPError(http.StatusUnauthorized, "missing authorization header")
34				}
35	
36				parts := strings.SplitN(authHeader, " ", 2)
37				if len(parts) != 2 || strings.ToLower(parts[0]) != "bearer" {
38					return echo.NewHTTPError(http.StatusUnauthorized, "invalid authorization format")
39				}
40	
41				claims, err := jwt.ValidateToken(parts[1])
42				if err != nil {
43					return echo.NewHTTPError(http.StatusUnauthorized, "invalid or expired token")
44				}
45	
46				// Validate session (idle timeout / max lifetime)
47				session, err := m.authService.ValidateSession(c.Request().Context(), claims.SessionID)
48				if err != nil || session == nil {
49					return echo.NewHTTPError(http.StatusUnauthorized, "session expired")
50				}
51	
52				// Store claims in context for downstream handlers
53				c.Set("claims", claims)
54				c.Set("user_id", claims.UserID)
55				c.Set("username", claims.Username)
56				c.Set("roles", claims.Roles)
57				c.Set("permissions", claims.Permissions)
58				c.Set("session_id", claims.SessionID)
59	
60				return next(c)
61			}
62		}
63	}
64	
65	// RequireRole checks that the authenticated user has at least one of the specified roles.
66	// Returns 404 Not Found (not 403) so unauthorized users cannot discover that a feature exists.
67	func (m *AuthMiddleware) RequireRole(roles ...string) echo.MiddlewareFunc {
68		return func(next echo.HandlerFunc) echo.HandlerFunc {
69			return func(c echo.Context) error {
70				userRoles, ok := c.Get("roles").([]string)
71				if !ok || len(userRoles) == 0 {
72					return echo.NewHTTPError(http.StatusNotFound)
73				}
74	
75				for _, required := range roles {
76					for _, userRole := range userRoles {
77						if required == userRole {
78							return next(c)
79						}
80					}
81				}
82	
83				// Feature invisibility: user without the role should not know the endpoint exists
84				return echo.NewHTTPError(http.StatusNotFound)
85			}
86		}
87	}
88	
89	// RequirePermission checks that the authenticated user has at least one of the specified permissions.
90	// Returns 404 Not Found (not 403) so unauthorized users cannot discover that a feature exists.
91	func (m *AuthMiddleware) RequirePermission(perms ...string) echo.MiddlewareFunc {
92		return func(next echo.HandlerFunc) echo.HandlerFunc {
93			return func(c echo.Context) error {
94				userPerms, ok := c.Get("permissions").([]string)
95				if !ok || len(userPerms) == 0 {
96					return echo.NewHTTPError(http.StatusNotFound)
97				}
98	
99				for _, required := range perms {
100					for _, userPerm := range userPerms {
101						if required == userPerm {
102							return next(c)
103						}
104					}
105				}
106	
107				return echo.NewHTTPError(http.StatusNotFound)
108			}
109		}
110	}
111	
112	// AppVersionCheck middleware checks the client's app version header and enforces compatibility.
113	// Clients below the minimum supported version enter a 14-day (configurable) read-only grace
114	// period. During grace, GET/HEAD/OPTIONS requests are allowed but writes are blocked.
115	// After the grace period expires, all requests are blocked.
116	func (m *AuthMiddleware) AppVersionCheck() echo.MiddlewareFunc {
117		return func(next echo.HandlerFunc) echo.HandlerFunc {
118			return func(c echo.Context) error {
119				clientVersion := c.Request().Header.Get("X-App-Version")
120				if clientVersion == "" {
121					return next(c) // Allow requests without version header (browser clients)
122				}
123	
124				minVersion, _ := m.configService.GetConfig("app.min_supported_version")
125				if minVersion == "" {
126					return next(c)
127				}
128	
129				if compareVersions(clientVersion, minVersion) < 0 {
130					// Determine grace period: how long the min_version has been in effect
131					graceDays := 14
132					if val, ok := m.configService.GetConfig("app.read_only_grace_days"); ok {
133						var d int
134						if _, err := fmt.Sscanf(val, "%d", &d); err == nil && d > 0 {
135							graceDays = d
136						}
137					}
138	
139					// Get the timestamp when the min_supported_version was last updated
140					// (approximated by the config's updated_at). If not available, treat
141					// as if just updated (full grace period).
142					minVersionSetAt := m.configService.GetConfigUpdatedAt("app.min_supported_version")
143	
144					graceDeadline := minVersionSetAt.Add(time.Duration(graceDays) * 24 * time.Hour)
145					withinGrace := time.Now().Before(graceDeadline)
146	
147					c.Response().Header().Set("X-App-Deprecated", "true")
148					c.Response().Header().Set("X-Min-Version", minVersion)
149	
150					if !withinGrace {
151						// Grace period expired: hard block ALL requests
152						return echo.NewHTTPError(http.StatusUpgradeRequired,
153							"client version unsupported and grace period expired; upgrade to "+minVersion+" or later")
154					}
155	
156					// Within grace period: allow read-only access
157					c.Set("read_only", true)
158					daysLeft := int(time.Until(graceDeadline).Hours() / 24)
159					c.Response().Header().Set("X-Grace-Days-Remaining", fmt.Sprintf("%d", daysLeft))
160	
161					method := c.Request().Method
162					if method == "POST" || method == "PUT" || method == "PATCH" || method == "DELETE" {
163						return echo.NewHTTPError(http.StatusUpgradeRequired,
164							fmt.Sprintf("client version unsupported; read-only access for %d more days. Upgrade to %s or later.",
165								daysLeft, minVersion))
166					}
167				}
168	
169				return next(c)
170			}
171		}
172	}
