26			flags:      make(map[string]models.FeatureFlag),
27		}
28	}
29	
30	// LoadAll fetches all configs and flags from DB into the in-memory cache.
31	func (s *ConfigService) LoadAll(ctx context.Context) error {
32		configs, err := s.configRepo.GetAllConfigs(ctx)
33		if err != nil {
34			return err
35		}
36		flags, err := s.configRepo.GetAllFeatureFlags(ctx)
37		if err != nil {
38			return err
39		}
40	
41		s.mu.Lock()
42		defer s.mu.Unlock()
43	
44		s.configs = make(map[string]models.Config, len(configs))
45		for _, c := range configs {
46			s.configs[c.Key] = c
47		}
48	
49		s.flags = make(map[string]models.FeatureFlag, len(flags))
50		for _, f := range flags {
51			s.flags[f.Key] = f
52		}
53	
54		return nil
55	}
