57	// StartBackgroundSync periodically refreshes the in-memory cache from DB.
58	func (s *ConfigService) StartBackgroundSync(ctx context.Context, interval time.Duration) {
59		go func() {
60			ticker := time.NewTicker(interval)
61			defer ticker.Stop()
62			for {
63				select {
64				case <-ctx.Done():
65					return
66				case <-ticker.C:
67					if err := s.LoadAll(ctx); err != nil {
68						log.Printf("[config-sync] failed to reload configs: %v", err)
69					}
70				}
71			}
72		}()
73	}
74	
75	// GetConfig returns a cached config value. Falls through to DB on cache miss.
76	func (s *ConfigService) GetConfig(key string) (string, bool) {
77		s.mu.RLock()
78		defer s.mu.RUnlock()
79		c, ok := s.configs[key]
80		if !ok {
81			return "", false
82		}
83		return c.Value, true
84	}
85	
86	// GetConfigUpdatedAt returns the updated_at timestamp for a config key.
87	// Returns time.Now() if the key is not found (conservative: full grace period).
88	func (s *ConfigService) GetConfigUpdatedAt(key string) time.Time {
89		s.mu.RLock()
90		defer s.mu.RUnlock()
91		c, ok := s.configs[key]
92		if !ok {
93			return time.Now()
94		}
95		return c.UpdatedAt
96	}
97	
98	// GetAllConfigs returns all cached configs.
99	func (s *ConfigService) GetAllConfigs() []models.Config {
100		s.mu.RLock()
101		defer s.mu.RUnlock()
102		result := make([]models.Config, 0, len(s.configs))
103		for _, c := range s.configs {
104			result = append(result, c)
105		}
106		return result
107	}
