110	func (s *ConfigService) GetAllFlags() []models.FeatureFlag {
111		s.mu.RLock()
112		defer s.mu.RUnlock()
113		result := make([]models.FeatureFlag, 0, len(s.flags))
114		for _, f := range s.flags {
115			result = append(result, f)
116		}
117		return result
118	}
119	
120	// IsFlagEnabled checks if a feature flag is enabled for a given user's roles.
121	func (s *ConfigService) IsFlagEnabled(key string, userRoleIDs []int) bool {
122		s.mu.RLock()
123		defer s.mu.RUnlock()
124	
125		f, ok := s.flags[key]
126		if !ok || !f.Enabled {
127			return false
128		}
129	
130		switch f.RolloutStrategy {
131		case "all":
132			return true
133		case "disabled":
134			return false
135		case "role_based":
136			for _, allowed := range f.AllowedRoles {
137				for _, userRole := range userRoleIDs {
138					if allowed == userRole {
139						return true
140					}
141				}
142			}
143			return false
144		case "percentage":
145			// For percentage-based, we use a deterministic hash of the key
146			// In a real impl, you'd hash user_id + flag_key for consistent bucketing.
147			// For now, just check if the percentage > 0 means enabled.
148			return f.RolloutPercentage > 0
149		default:
150			return false
151		}
152	}
