	})

	req := httptest.NewRequest(http.MethodGet, "/test", nil)
	req.Header.Set("X-App-Version", "1.0.0")
	rec := httptest.NewRecorder()
	e.ServeHTTP(rec, req)

	if rec.Code != http.StatusOK {
