13	// ConfigService provides in-memory cached access to configs and feature flags.
14	type ConfigService struct {
15		configRepo *repository.ConfigRepository
16	
17		mu      sync.RWMutex
18		configs map[string]models.Config
19		flags   map[string]models.FeatureFlag
20	}
21	
22	func NewConfigService(configRepo *repository.ConfigRepository) *ConfigService {
23		return &ConfigService{
24			configRepo: configRepo,
25			configs:    make(map[string]models.Config),
26			flags:      make(map[string]models.FeatureFlag),
27		}
28	}
29	
30	// NewConfigServiceForTest creates a ConfigService with pre-loaded configs for testing
31	// without requiring a database connection.
32	func NewConfigServiceForTest(configs map[string]models.Config) *ConfigService {
33		return &ConfigService{
34			configs: configs,
35			flags:   make(map[string]models.FeatureFlag),
36		}
37	}
38	
39	// LoadAll fetches all configs and flags from DB into the in-memory cache.
40	func (s *ConfigService) LoadAll(ctx context.Context) error {
41		configs, err := s.configRepo.GetAllConfigs(ctx)
42		if err != nil {
43			return err
44		}
45		flags, err := s.configRepo.GetAllFeatureFlags(ctx)
46		if err != nil {
47			return err
48		}
49	
50		s.mu.Lock()
51		defer s.mu.Unlock()
52	
53		s.configs = make(map[string]models.Config, len(configs))
54		for _, c := range configs {
55			s.configs[c.Key] = c
56		}
57	
58		s.flags = make(map[string]models.FeatureFlag, len(flags))
59		for _, f := range flags {
60			s.flags[f.Key] = f
61		}
62	
63		return nil
64	}
65	
66	// StartBackgroundSync periodically refreshes the in-memory cache from DB.
67	func (s *ConfigService) StartBackgroundSync(ctx context.Context, interval time.Duration) {
68		go func() {
69			ticker := time.NewTicker(interval)
70			defer ticker.Stop()
71			for {
72				select {
73				case <-ctx.Done():
74					return
75				case <-ticker.C:
76					if err := s.LoadAll(ctx); err != nil {
77						log.Printf("[config-sync] failed to reload configs: %v", err)
78					}
79				}
80			}
81		}()
82	}
83	
84	// GetConfig returns a cached config value. Falls through to DB on cache miss.
85	func (s *ConfigService) GetConfig(key string) (string, bool) {
86		s.mu.RLock()
87		defer s.mu.RUnlock()
88		c, ok := s.configs[key]
89		if !ok {
90			return "", false
91		}
92		return c.Value, true
93	}
94	
95	// GetConfigUpdatedAt returns the updated_at timestamp for a config key.
96	// Returns time.Now() if the key is not found (conservative: full grace period).
97	func (s *ConfigService) GetConfigUpdatedAt(key string) time.Time {
98		s.mu.RLock()
99		defer s.mu.RUnlock()
100		c, ok := s.configs[key]
101		if !ok {
102			return time.Now()
103		}
104		return c.UpdatedAt
105	}
106	
107	// GetAllConfigs returns all cached configs.
108	func (s *ConfigService) GetAllConfigs() []models.Config {
109		s.mu.RLock()
110		defer s.mu.RUnlock()
111		result := make([]models.Config, 0, len(s.configs))
112		for _, c := range s.configs {
113			result = append(result, c)
114		}
115		return result
116	}
117	
118	// GetAllFlags returns all cached feature flags.
119	func (s *ConfigService) GetAllFlags() []models.FeatureFlag {
120		s.mu.RLock()
121		defer s.mu.RUnlock()
122		result := make([]models.FeatureFlag, 0, len(s.flags))
123		for _, f := range s.flags {
124			result = append(result, f)
125		}
126		return result
127	}
128	
129	// IsFlagEnabled checks if a feature flag is enabled for a given user's roles.
130	func (s *ConfigService) IsFlagEnabled(key string, userRoleIDs []int) bool {
131		s.mu.RLock()
132		defer s.mu.RUnlock()
133	
134		f, ok := s.flags[key]
135		if !ok || !f.Enabled {
136			return false
137		}
138	
139		switch f.RolloutStrategy {
140		case "all":
141			return true
142		case "disabled":
143			return false
144		case "role_based":
145			for _, allowed := range f.AllowedRoles {
146				for _, userRole := range userRoleIDs {
147					if allowed == userRole {
148						return true
149					}
150				}
151			}
152			return false
153		case "percentage":
154			// For percentage-based, we use a deterministic hash of the key
155			// In a real impl, you'd hash user_id + flag_key for consistent bucketing.
156			// For now, just check if the percentage > 0 means enabled.
157			return f.RolloutPercentage > 0
158		default:
159			return false
160		}
161	}
162	
163	// UpdateConfig updates a config in DB and refreshes cache.
164	func (s *ConfigService) UpdateConfig(ctx context.Context, key, value string, updatedBy int) error {
165		if err := s.configRepo.UpdateConfig(ctx, key, value, updatedBy); err != nil {
166			return err
167		}
168		return s.LoadAll(ctx)
169	}
170	
171	// UpdateFeatureFlag updates a flag in DB and refreshes cache.
172	func (s *ConfigService) UpdateFeatureFlag(ctx context.Context, key string, req models.FeatureFlagUpdateRequest) error {
173		if err := s.configRepo.UpdateFeatureFlag(ctx, key, req); err != nil {
174			return err
175		}
176		return s.LoadAll(ctx)
177	}
