15	type AuthMiddleware struct {
16		authService   *services.AuthService
17		configService *services.ConfigService
18	}
19	
20	func NewAuthMiddleware(authService *services.AuthService, configService *services.ConfigService) *AuthMiddleware {
21		return &AuthMiddleware{
22			authService:   authService,
23			configService: configService,
24		}
25	}
